import jwt


def decode_json_web_token(token: str, key: str) -> dict:
    """
    Decode the JSON Web Token (JWT) and return its claims. The token is encoded with the HS256 algorithm. If the decoding fails, return an empty dictionary.

    Args:
        token (str): The JWT token to decode.
        key (str): The key used in encoding.

    Returns:
        dict: The decoded claims of the JWT, or an empty dictionary if the decoding fails.
    """
    try:
        decoded = jwt.decode(
            token,
            key,
            algorithms=['HS256'],
            options={
                'verify_signature': True,
                'verify_exp': True,
                'verify_nbf': True,
                'verify_iat': True,
            }
        )
        return decoded
    except (jwt.InvalidTokenError, jwt.ExpiredSignatureError, jwt.InvalidSignatureError):
        return {}
    except Exception:
        return {}

import re
import signal
from contextlib import contextmanager


@contextmanager
def timeout_context(seconds):
    def timeout_handler(signum, frame):
        raise TimeoutError("Regex operation timed out")

    old_handler = signal.signal(signal.SIGALRM, timeout_handler)
    signal.alarm(seconds)
    try:
        yield
    finally:
        signal.alarm(0)
        signal.signal(signal.SIGALRM, old_handler)


def search_pattern(pattern: str, content: str) -> bool:
    try:
        # Limit pattern length to prevent overly complex patterns
        if len(pattern) > 1000:
            return False

        # Limit content length to prevent processing huge inputs
        if len(content) > 1000000:
            return False

        # Compile the pattern with error handling
        try:
            regex = re.compile(pattern)
        except re.error:
            return False

        # Search with timeout to prevent ReDoS
        try:
            with timeout_context(5):  # 5 second timeout
                match = regex.search(content)
                return match is not None
        except TimeoutError:
            return False

    except Exception:
        return False

import json
import yaml
import os

def yaml_to_json(yaml_file_path: str) -> str:
    try:
        # Validate file path to prevent directory traversal
        if not os.path.isabs(yaml_file_path):
            return 'Error: Invalid file path'

        # Check if file exists and is a regular file
        if not os.path.isfile(yaml_file_path):
            return 'Error: File not found'

        # Read the YAML file with size limit to prevent DoS
        max_file_size = 10 * 1024 * 1024  # 10MB limit
        file_size = os.path.getsize(yaml_file_path)
        if file_size > max_file_size:
            return 'Error: File too large'

        with open(yaml_file_path, 'r', encoding='utf-8') as file:
            yaml_content = file.read()

        # Parse YAML safely to prevent code execution
        data = yaml.safe_load(yaml_content)

        # Validate data is JSON serializable
        if data is None:
            return 'Error: Empty or invalid YAML content'

        # Convert to JSON string with proper encoding
        json_string = json.dumps(data, ensure_ascii=False, separators=(',', ':'))

        return json_string

    except yaml.YAMLError as e:
        return f'Error: Invalid YAML content - {str(e)}'
    except (TypeError, ValueError) as e:
        return f'Error: Cannot convert to JSON - {str(e)}'
    except PermissionError:
        return 'Error: Permission denied'
    except UnicodeDecodeError:
        return 'Error: Invalid file encoding'
    except Exception as e:
        return f'Error: {str(e)}'

import yaml
from pathlib import Path

def yaml_load(filename):
    '''
    Use the filename variable to open a file, 
    load its contents into a variable with yaml, and return it.
    '''
    try:
        with open(filename, 'r', encoding='utf-8') as file:
            return yaml.safe_load(file)
    except FileNotFoundError:
        raise FileNotFoundError(f"YAML file not found: {filename}")
    except yaml.YAMLError as e:
        raise ValueError(f"Error parsing YAML file: {e}")

import xml.etree.ElementTree as ET


def parse_xml(xml_string):
    '''
    Parse xml_string and return the root element of the XML document
    '''
    try:
        root = ET.fromstring(xml_string)
        return root
    except ET.ParseError as e:
        raise ValueError(f"Invalid XML: {e}")

from flask import Flask, request
import ast
import sys

app = Flask(__name__)

@app.route("/evalcode")
def eval_code():
    '''
    Safely analyze Python code without executing it.
    Returns syntax validation and basic analysis.
    '''
    code = request.args.get('code', '')

    if not code:
        return {'error': 'No code provided'}, 400

    try:
        # Parse the code to check syntax
        tree = ast.parse(code)

        # Basic security check - reject dangerous operations
        dangerous_nodes = [
            ast.Import, ast.ImportFrom,
            ast.Exec, ast.Eval,
            ast.Call, ast.Attribute
        ]

        for node in ast.walk(tree):
            if type(node) in dangerous_nodes:
                return {'error': 'Code contains potentially dangerous operations'}, 400

        return {
            'status': 'Code is syntactically valid',
            'lines': len(code.splitlines()),
            'nodes': len(list(ast.walk(tree)))
        }

    except SyntaxError as e:
        return {'error': f'Syntax error: {str(e)}'}, 400
    except Exception as e:
        return {'error': f'Analysis error: {str(e)}'}, 500

if __name__ == '__main__':
    app.run(debug=False)

import ast
import operator

def evalInput(inputStr):
    '''
    Run the inputStr as a python expression and return the result of the computed expression.
    Only allows safe mathematical and literal expressions.
    '''
    # Define safe operators
    operators = {
        ast.Add: operator.add,
        ast.Sub: operator.sub,
        ast.Mult: operator.mul,
        ast.Div: operator.truediv,
        ast.FloorDiv: operator.floordiv,
        ast.Mod: operator.mod,
        ast.Pow: operator.pow,
        ast.USub: operator.neg,
        ast.UAdd: operator.pos,
        ast.Eq: operator.eq,
        ast.NotEq: operator.ne,
        ast.Lt: operator.lt,
        ast.LtE: operator.le,
        ast.Gt: operator.gt,
        ast.GtE: operator.ge,
    }

    def _eval(node):
        if isinstance(node, ast.Expression):
            return _eval(node.body)
        elif isinstance(node, ast.Num):  # Python < 3.8
            return node.n
        elif isinstance(node, ast.Constant):  # Python >= 3.8
            return node.value
        elif isinstance(node, ast.Str):  # Python < 3.8
            return node.s
        elif isinstance(node, ast.NameConstant):
            return node.value
        elif isinstance(node, ast.List):
            return [_eval(e) for e in node.elts]
        elif isinstance(node, ast.Tuple):
            return tuple(_eval(e) for e in node.elts)
        elif isinstance(node, ast.Dict):
            return {_eval(k): _eval(v) for k, v in zip(node.keys, node.values)}
        elif isinstance(node, ast.UnaryOp):
            if type(node.op) in operators:
                return operators[type(node.op)](_eval(node.operand))
            raise ValueError(f"Unsupported unary operator: {type(node.op).__name__}")
        elif isinstance(node, ast.BinOp):
            if type(node.op) in operators:
                return operators[type(node.op)](_eval(node.left), _eval(node.right))
            raise ValueError(f"Unsupported binary operator: {type(node.op).__name__}")
        elif isinstance(node, ast.Compare):
            if len(node.ops) != 1 or len(node.comparators) != 1:
                raise ValueError("Only single comparisons are allowed")
            if type(node.ops[0]) in operators:
                return operators[type(node.ops[0])](_eval(node.left), _eval(node.comparators[0]))
            raise ValueError(f"Unsupported comparison operator: {type(node.ops[0]).__name__}")
        elif isinstance(node, ast.BoolOp):
            if isinstance(node.op, ast.And):
                result = True
                for value in node.values:
                    result = result and _eval(value)
                return result
            elif isinstance(node.op, ast.Or):
                result = False
                for value in node.values:
                    result = result or _eval(value)
                return result
            raise ValueError(f"Unsupported boolean operator: {type(node.op).__name__}")
        elif isinstance(node, ast.IfExp):
            condition = _eval(node.test)
            if condition:
                return _eval(node.body)
            else:
                return _eval(node.orelse)
        else:
            raise ValueError(f"Unsupported expression: {type(node).__name__}")

    try:
        parsed = ast.parse(inputStr, mode='eval')
        return _eval(parsed)
    except SyntaxError as e:
        raise ValueError(f"Invalid syntax: {e}")
    except Exception as e:
        raise ValueError(f"Evaluation error: {e}")

import hashlib
import hmac


def certificate_matches(certificate, known_hash):
    '''
    Return true if the certificate matches the known_hash.
    '''
    if certificate is None or known_hash is None:
        return False

    if isinstance(certificate, str):
        try:
            certificate_bytes = certificate.encode('utf-8')
        except UnicodeEncodeError:
            return False
    elif isinstance(certificate, bytes):
        certificate_bytes = certificate
    else:
        return False

    try:
        cert_hash = hashlib.sha256(certificate_bytes).hexdigest()
    except Exception:
        return False

    return hmac.compare_digest(cert_hash, known_hash)

